Config = Struct.new :relative_url_root, :api_only, :default_scope

DEFAULT_CONFIG = Config.new(nil, false, nil)

def initialize(config = DEFAULT_CONFIG.dup)
  self.named_routes = NamedRouteCollection.new
  self.resources_path_names = self.class.default_resources_path_names
  self.default_url_options = {}
  self.draw_paths = []

  @config                     = config
  @append                     = []
  @prepend                    = []
  @disable_clear_and_finalize = false
  @finalized                  = false
  @env_key                    = "ROUTES_#{object_id}_SCRIPT_NAME"
  @default_env                = nil

  @set    = Journey::Routes.new
  @router = Journey::Router.new @set
  @formatter = Journey::Formatter.new self
  @polymorphic_mappings = {}
end

def eager_load!
  router.eager_load!
  routes.each(&:eager_load!)
  formatter.eager_load!
  nil
end

def relative_url_root
  @config.relative_url_root
end

def api_only?
  @config.api_only
end

def default_scope
  @config.default_scope
end

def default_scope=(new_default_scope)
  @config.default_scope = new_default_scope
end

def request_class
  ActionDispatch::Request
end

def make_request(env)
  request_class.new env
end
private :make_request

def default_env
  if default_url_options != @default_env&.[]("action_dispatch.routes.default_url_options")
    url_options = default_url_options.dup.freeze
    uri = URI(ActionDispatch::Http::URL.full_url_for(host: "example.org", **url_options))

    @default_env = {
      "action_dispatch.routes" => self,
      "action_dispatch.routes.default_url_options" => url_options,
      "HTTPS" => uri.scheme == "https" ? "on" : "off",
      "rack.url_scheme" => uri.scheme,
      "HTTP_HOST" => uri.port == uri.default_port ? uri.host : "#{uri.host}:#{uri.port}",
      "SCRIPT_NAME" => uri.path.chomp("/"),
      "rack.input" => "",
    }.freeze
  end

  @default_env
end

def draw(&block)
  clear! unless @disable_clear_and_finalize
  eval_block(block)
  finalize! unless @disable_clear_and_finalize
  nil
end

def append(&block)
  @append << block
end

def prepend(&block)
  @prepend << block
end

def eval_block(block)
  mapper = Mapper.new(self)
  if default_scope
    mapper.with_default_scope(default_scope, &block)
  else
    mapper.instance_exec(&block)
  end
end
private :eval_block

def finalize!
  return if @finalized
  @append.each { |blk| eval_block(blk) }
  @finalized = true
end

def clear!
  @finalized = false

class Mapping # :nodoc:
  ANCHOR_CHARACTERS_REGEX = %r{\A(\\A|\^)|(\\Z|\\z|\$)\Z}
  OPTIONAL_FORMAT_REGEX = %r{(?:\(\.:format\)+|\.:format|/)\Z}

  attr_reader :path, :requirements, :defaults, :to, :default_controller,
              :default_action, :required_defaults, :ast, :scope_options

  def self.build(scope, set, ast, controller, default_action, to, via, formatted, options_constraints, anchor, internal, options)
    scope_params = {
      blocks: scope[:blocks] || [],
      constraints: scope[:constraints] || {},
      defaults: (scope[:defaults] || {}).dup,
      module: scope[:module],
      options: scope[:options] || {}
    }

    new set: set, ast: ast, controller: controller, default_action: default_action,
        to: to, formatted: formatted, via: via, options_constraints: options_constraints,
        anchor: anchor, scope_params: scope_params, internal: internal, options: scope_params[:options].merge(options)
  end

  def self.check_via(via)
    if via.empty?
      msg = "You should not use the `match` method in your router without specifying an HTTP method.\n" \
        "If you want to expose your action to both GET and POST, add `via: [:get, :post]` option.\n" \
        "If you want to expose your action to GET, use `get` in the router:\n" \
        "  Instead of: match \"controller#action\"\n" \
        "  Do: get \"controller#action\""
      raise ArgumentError, msg
    end
    via
  end

  def self.normalize_path(path, format)
    path = Mapper.normalize_path(path)

    if format == true
      "#{path}.:format"
    elsif optional_format?(path, format)
      "#{path}(.:format)"
    else
      path
    end
  end

  def self.optional_format?(path, format)
    format != false && !path.match?(OPTIONAL_FORMAT_REGEX)
  end

  def initialize(set:, ast:, controller:, default_action:, to:, formatted:, via:, options_constraints:, anchor:, scope_params:, internal:, options:)
    @defaults           = scope_params[:defaults]
    @set                = set
    @to                 = intern(to)
    @default_controller = intern(controller)
    @default_action     = intern(default_action)
    @anchor             = anchor
    @via                = via
    @internal           = internal
    @scope_options      = scope_params[:options]
    ast                 = Journey::Ast.new(ast, formatted)

    options = ast.wildcard_options.merge!(options)

    options = normalize_options!(options, ast.path_params, scope_params[:module])

    split_options = constraints(options, ast.path_params)

    constraints = scope_params[:constraints].merge Hash[split_options[:constraints] || []]

    if options_constraints.is_a?(Hash)
      @defaults = Hash[options_constraints.find_all { |key, default|
        URL_OPTIONS.include?(key) && (String === default || Integer === default)
      }].merge @defaults
      @blocks = scope_params[:blocks]
      constraints.merge! options_constraints
    else
      @blocks = blocks(options_constraints)
    end

    requirements, conditions = split_constraints ast.path_params, constraints
    verify_regexp_requirements requirements, ast.wildcard_options

    formats = normalize_format(formatted)

    @requirements = formats[:requirements].merge Hash[requirements]
    @conditions = Hash[conditions]
    @defaults = formats[:defaults].merge(@defaults).merge(normalize_defaults(options))

    if ast.path_params.include?(:action) && !@requirements.key?(:action)
      @defaults[:action] ||= "index"
    end

    @required_defaults = (split_options[:required_defaults] || []).map(&:first)

    ast.requirements = @requirements
    @path = Journey::Path::Pattern.new(ast, @requirements, JOINED_SEPARATORS, @anchor)
  end

  JOINED_SEPARATORS = SEPARATORS.join # :nodoc:

  def make_route(name, precedence)
    Journey::Route.new(name: name, app: application, path: path, constraints: conditions,
                       required_defaults: required_defaults, defaults: defaults,
                       via: @via, precedence: precedence,
                       scope_options: scope_options, internal: @internal, source_location: route_source_location)
  end

  def application
    app(@blocks)
  end

  def conditions
    build_conditions @conditions, @set.request_class
  end

  def build_conditions(current_conditions, request_class)
    conditions = current_conditions.dup

    conditions.keep_if do |k, _|
      request_class.public_method_defined?(k)

