module ActionDispatch
  # :stopdoc:
  module Journey
    class Route
      attr_reader :app, :path, :defaults, :name, :precedence, :constraints,
                  :internal, :scope_options, :ast, :source_location

      alias :conditions :constraints

      module VerbMatchers
        VERBS = %w{ DELETE GET HEAD OPTIONS LINK PATCH POST PUT TRACE UNLINK }.freeze
        VERBS.each do |v|
          class_eval <<-eoc, __FILE__, __LINE__ + 1
            # frozen_string_literal: true
            class #{v}
              def self.verb; name.split("::").last; end
              def self.call(req); req.#{v.downcase}?; end
            end
          eoc
        end

        class Unknown
          attr_reader :verb

          def initialize(verb)
            @verb = verb
          end

          def call(request); @verb == request.request_method; end
        end

        class All
          def self.call(_); true; end
          def self.verb; ""; end
        end

        class Or
          attr_reader :verb

          def initialize(verbs)
            @verbs = verbs
            @verb = @verbs.map(&:verb).join("|")
          end

          def call(req)
            @verbs.any? { |v| v.call req }
          end
        end

        VERB_TO_CLASS = VERBS.each_with_object(all: All) do |verb, hash|
          klass = const_get verb
          hash[verb]                 = klass
          hash[verb.downcase]        = klass
          hash[verb.downcase.to_sym] = klass
        end

        VERB_TO_CLASS.default_proc = proc do |_, verb|
          VerbMatchers::Unknown.new verb.to_s.dasherize.upcase
        end

        def self.for(verbs)
          if verbs.any? { |v| VERB_TO_CLASS[v] == All }
            All
          elsif verbs.one?
            VERB_TO_CLASS[verbs.first]
          else
            Or.new(verbs.map { |v| VERB_TO_CLASS[v] })
          end
        end
      end

      ##
      # +path+ is a path constraint.
      # `constraints` is a hash of constraints to be applied to this route.
      def initialize(name:, app: nil, path:, constraints: {}, required_defaults: [], defaults: {}, via: nil, precedence: 0, scope_options: {}, internal: false, source_location: nil)
        @name        = name
        @app         = app
        @path        = path

        @request_method_match = via && VerbMatchers.for(via)
        @constraints = constraints
        @defaults    = defaults
        @required_defaults = nil
        @_required_defaults = required_defaults
        @required_parts    = nil
        @parts             = nil
        @precedence        = precedence
        @path_formatter    = @path.build_formatter
        @scope_options     = scope_options
        @internal          = internal
        @source_location   = source_location

        @ast = @path.ast.root
        @path.ast.route = self
      end
